#version 300 es
precision highp float;
uniform sampler2D u_input;
uniform float u_intensity;
uniform float u_speed;
uniform float u_tint;
uniform float u_time;
in vec2 v_texCoord;
out vec4 fragColor;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7))) * 43758.5453); }
void main(){
  vec2 uv = v_texCoord;
  float amt = clamp(u_intensity, 0.0, 1.0);
  float t = u_time * (0.35 + u_speed * 1.8);
  // rain streaks
  float streak = 0.0;
  for (int i = 0; i < 3; i++) {
    float fi = float(i);
    vec2 g = vec2(uv.x * (18.0 + fi * 9.0), uv.y * (6.0 + fi * 2.0) - t * (1.2 + fi * 0.4));
    vec2 id = floor(g);
    vec2 f = fract(g);
    float n = hash(id + fi * 17.0);
    float drop = smoothstep(0.12, 0.0, abs(f.x - 0.5 - (n - 0.5) * 0.25))
               * smoothstep(0.0, 0.15, f.y) * smoothstep(1.0, 0.55, f.y);
    streak += drop * (0.35 + 0.65 * n);
  }
  streak = clamp(streak, 0.0, 1.0) * amt;
  // slight UV warp like wet glass
  vec2 warp = vec2(streak * 0.008, 0.0);
  vec4 c = texture(u_input, uv + warp);
  // cool night tint
  vec3 cool = vec3(0.88, 0.94, 1.08);
  vec3 warm = vec3(1.05, 0.98, 0.92);
  vec3 grade = mix(vec3(1.0), mix(cool, warm, clamp(u_tint, 0.0, 1.0)), amt * 0.55);
  // fog at edges
  vec2 d = uv - 0.5;
  float fog = smoothstep(0.15, 0.75, length(d)) * amt * 0.22;
  vec3 col = c.rgb * grade;
  col = mix(col, col * 0.75 + vec3(0.12, 0.14, 0.18), fog);
  col += streak * 0.18;
  fragColor = vec4(col, c.a);
}

#version 300 es
precision highp float;
uniform sampler2D u_outgoing;
uniform sampler2D u_incoming;
uniform float u_progress;
uniform float u_intensity;
uniform float u_warmth;
uniform float u_spread;
in vec2 v_texCoord;
out vec4 fragColor;

float hash(vec2 p) {
  return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123);
}
float noise(vec2 p) {
  vec2 i = floor(p);
  vec2 f = fract(p);
  float a = hash(i);
  float b = hash(i + vec2(1.0, 0.0));
  float c = hash(i + vec2(0.0, 1.0));
  float d = hash(i + vec2(1.0, 1.0));
  vec2 u = f * f * (3.0 - 2.0 * f);
  return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}
float fbm(vec2 p) {
  float v = 0.0;
  float a = 0.5;
  for (int i = 0; i < 4; i++) {
    v += a * noise(p);
    p *= 2.05;
    a *= 0.5;
  }
  return v;
}
float ease(float t) {
  return t * t * (3.0 - 2.0 * t);
}

void main() {
  float p = clamp(u_progress, 0.0, 1.0);
  vec2 uv = v_texCoord;
  vec4 colA = texture(u_outgoing, uv);
  vec4 colB = texture(u_incoming, uv);

  // 双光心: 对角扫过,像镜头漏光
  float spread = 0.35 + clamp(u_spread, 0.0, 1.0) * 1.1;
  vec2 c1 = vec2(-0.15 + p * 1.35, 0.15 + p * 0.55);
  vec2 c2 = vec2(1.15 - p * 1.2, 0.9 - p * 0.4);
  float n = fbm(uv * (2.2 + spread) + vec2(p * 1.7, p * -0.9));
  float d1 = length((uv - c1) * vec2(1.35, 1.0));
  float d2 = length((uv - c2) * vec2(1.1, 1.25));
  float blob = exp(-d1 * d1 * (3.2 / spread)) + exp(-d2 * d2 * (2.6 / spread));
  blob = clamp(blob + (n - 0.5) * 0.55, 0.0, 2.5);

  // 0→0.5 漏光盖住 A 并过曝; 0.5→1 露出 B 且漏光退
  float cover = ease(smoothstep(0.0, 0.52, p));
  float reveal = ease(smoothstep(0.38, 1.0, p));
  float mixAB = reveal;
  vec3 base = mix(colA.rgb, colB.rgb, mixAB);

  float warm = clamp(u_warmth, 0.0, 1.0);
  vec3 leakColor = mix(vec3(1.0, 0.55, 0.22), vec3(1.0, 0.28, 0.55), warm);
  leakColor = mix(leakColor, vec3(1.0, 0.92, 0.65), 0.25);

  float inten = 0.55 + clamp(u_intensity, 0.0, 1.0) * 1.35;
  // 中段最强
  float peak = sin(p * 3.14159265);
  float leakAmt = blob * peak * inten * (0.45 + cover * 0.9);

  vec3 blown = base * (1.0 + leakAmt * 0.85) + leakColor * leakAmt;
  // 轻微色散
  float ca = leakAmt * 0.012;
  vec3 split = vec3(
    texture(u_outgoing, uv + vec2(ca, 0.0)).r * (1.0 - mixAB) + texture(u_incoming, uv + vec2(ca, 0.0)).r * mixAB,
    base.g,
    texture(u_outgoing, uv - vec2(ca, 0.0)).b * (1.0 - mixAB) + texture(u_incoming, uv - vec2(ca, 0.0)).b * mixAB
  );
  vec3 col = mix(blown, split + leakColor * leakAmt * 0.35, 0.35);
  col = clamp(col, 0.0, 1.0);
  fragColor = vec4(col, 1.0);
}

