const HouyeNamecard = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps, width, height } = useVideoConfig();
  const p = item.props || {};
  const name = String(p.name ?? "后夜来客");
  const role = String(p.role ?? "GUEST");
  const line = String(p.line ?? "说点什么");
  const accent = String(p.accent ?? "#6cf0c2");
  const s = height / 1080;
  const left = Math.round(width * 0.055);
  const bottom = Math.round(height * 0.12);
  const inA = spring({ frame, fps, config: { damping: 18, stiffness: 140, mass: 0.85 } });
  const inB = spring({ frame: frame - 5, fps, config: { damping: 200 } });
  const inC = spring({ frame: frame - 10, fps, config: { damping: 200 } });
  const hold = Math.round(fps * 4.2);
  const out = frame < hold ? 1 : Math.max(0, 1 - (frame - hold) / (fps * 0.45));
  const op = inA * out;
  const slide = (1 - inA) * 48 * s;
  return (
    <AbsoluteFill style={{ pointerEvents: "none", fontFamily: "system-ui, -apple-system, 'Segoe UI', 'PingFang SC', 'Noto Sans SC', sans-serif" }}>
      <div style={{
        position: "absolute", left, bottom,
        transform: `translateX(${-slide}px)`,
        opacity: op,
        display: "flex",
        alignItems: "stretch",
        gap: 0,
      }}>
        <div style={{
          width: 5 * s,
          background: accent,
          borderRadius: 3 * s,
          boxShadow: `0 0 18px ${accent}88`,
          transform: `scaleY(${inB})`,
          transformOrigin: "center bottom",
        }} />
        <div style={{ paddingLeft: 18 * s, paddingTop: 4 * s, paddingBottom: 4 * s }}>
          <div style={{
            fontSize: 13 * s,
            fontWeight: 700,
            letterSpacing: 3 * s,
            color: accent,
            opacity: 0.95,
            textTransform: "uppercase",
          }}>{role}</div>
          <div style={{
            marginTop: 6 * s,
            fontSize: 46 * s,
            fontWeight: 800,
            color: "#f2ebe0",
            letterSpacing: 1 * s,
            lineHeight: 1.1,
            textShadow: "0 4px 28px rgba(0,0,0,0.55)",
          }}>{name}</div>
          <div style={{
            marginTop: 10 * s,
            fontSize: 16 * s,
            fontWeight: 500,
            color: "rgba(242,235,224,0.72)",
            maxWidth: 520 * s,
          }}>{line}</div>
          <div style={{
            marginTop: 14 * s,
            height: 2 * s,
            width: 160 * s * inC,
            background: accent,
            borderRadius: 2 * s,
            boxShadow: `0 0 12px ${accent}`,
          }} />
        </div>
      </div>
    </AbsoluteFill>
  );
};
